using Microsoft.AspNetCore.Authorization; using Microsoft.AspNetCore.Mvc; using System.Security.Claims; using Valora.Application.Contracts; using Valora.Application.DTOs;
namespace Valora.Api.Controllers; [ApiController] public sealed class LgpdController(ILgpdConsentService consents,IPrivacyRequestService privacy):ControllerBase{ Guid Org=>Guid.Parse(User.FindFirstValue("organization_id")??Guid.Empty.ToString()); Guid? UserId=>Guid.TryParse(User.FindFirstValue(ClaimTypes.NameIdentifier),out var id)?id:null; [HttpPost("/public/lgpd/requests")] public async Task<IActionResult> PublicCreate([FromBody]CreatePrivacyRequestRequest r)=>Ok(new{ok=true,request=await privacy.CreatePublicAsync(r)}); [HttpGet("/public/lgpd/requests/{protocol}")] public async Task<IActionResult> PublicGet(string protocol){var r=await privacy.GetPublicAsync(protocol); return r is null?NotFound():Ok(new{ok=true,request=r});} [Authorize][HttpGet("/lgpd/consents")] public async Task<IActionResult> Consents()=>Ok(new{ok=true,data=await consents.ListAsync(Org)}); [Authorize][HttpGet("/lgpd/privacy-requests")] public async Task<IActionResult> Requests()=>Ok(new{ok=true,data=await privacy.ListAsync(Org)}); [Authorize][HttpGet("/lgpd/privacy-requests/{id:guid}")] public async Task<IActionResult> Request(Guid id)=>Ok(new{ok=true,request=await privacy.ListAsync(Org).ContinueWith(t=>t.Result.FirstOrDefault(x=>x.Id==id))}); [Authorize][HttpPatch("/lgpd/privacy-requests/{id:guid}/status")] public async Task<IActionResult> Status(Guid id,[FromBody]UpdatePrivacyRequestStatusRequest r){await privacy.UpdateStatusAsync(Org,id,r.Status,UserId); return Ok(new{ok=true});} [Authorize][HttpPost("/lgpd/privacy-requests/{id:guid}/complete")] public async Task<IActionResult> Complete(Guid id,[FromBody]CompletePrivacyRequestRequest r){await privacy.CompleteAsync(Org,id,r.ResultJson,UserId); return Ok(new{ok=true});}}
